lunes.setHours(0, 0, 0, 0);

const semana = `${lunes.getFullYear()}-W${String(Math.ceil(lunes.getDate()/7)).padStart(2,'0')}-${lunes.getMonth()+1}`;

const deEstaSemana = archivos.filter(item => {
  const creado = new Date(item.json.createdTime);
  return creado >= lunes;
});

const pdfs = deEstaSemana.map(i => ({
  name: i.json.name,
  createdTime: i.json.createdTime
}));

// Pasar los PDFs como un solo item con todos los datos
return [{ json: { pdfs, semana, totalDrive: pdfs.length } }];

// Recibe los PDFs del paso anterior y los correos del nodo Gmail
// Los PDFs vienen en el primer item, los correos en los siguientes
const todosItems = $input.all();

// El primer item tiene los datos de Drive
const pdfData = $('Filtrar PDFs Esta Semana').first().json;
const pdfs = pdfData.pdfs || [];
const semana = pdfData.semana || '';

// Extraer archivos enviados de los correos
const archivosEnviados = new Set();
for (const item of todosItems) {
  const asunto = item.json.subject || '';
  const cuerpo = item.json.text || item.json.snippet || '';
  const html   = item.json.html || '';
  const todo   = asunto + ' ' + cuerpo + ' ' + html;

  const matches = todo.match(/[^\s"<>()\[\]]+\.pdf/gi);
  if (matches) {
    for (const m of matches) {
      archivosEnviados.add(m.trim().toLowerCase());
    }
  }
}

// Cruzar
const pendientes = [];
const enviadosOk = [];

for (const pdf of pdfs) {
  const nombre = (pdf.name || '').toLowerCase();
  const nombreSinExt = nombre.replace(/\.pdf$/i, '');

  const matchAlto = nombreSinExt.match(/_(\d+(?:[.,]\d+)?)$/);
  const altoCm = matchAlto ? parseFloat(matchAlto[1].replace(',', '.')) : 0;
  const metros = altoCm > 0 ? Math.round((altoCm / 100) * 1000) / 1000 : 0;

  const yaEnviado = Array.from(archivosEnviados).some(e => {
    const eSinExt = e.replace(/\.pdf$/i, '');
    return e === nombre || eSinExt === nombreSinExt ||
           e.includes(nombreSinExt) || nombreSinExt.includes(eSinExt);
  });

  const fecha = new Date(pdf.createdTime);
  const fechaStr = fecha.toLocaleDateString('es-CO', { weekday: 'short', day: 'numeric', month: 'short' });

  if (yaEnviado) {
    enviadosOk.push({ nombre: pdf.name, fecha: fechaStr, altoCm, metros });
  } else {
    pendientes.push({ nombre: pdf.name, fecha: fechaStr, altoCm, metros });
  }
}

return [{ json: {
  semana,
  hayPendientes: pendientes.length > 0,
  pendientes,
  enviadosOk,
  totalDrive: pdfs.length,
  totalEnviados: enviadosOk.length,
  totalPendientes: pendientes.length
} }];

const data = $('Cruzar Drive vs WeTransfer').first().json;
const pendientes = data.pendientes || [];

let lista = '';
for (const p of pendientes) {
  lista += `\n• ${p.nombre} (${p.fecha})`;
}

const mensaje = `⚠️ PDFs sin enviar por WeTransfer\n\n` +
  `Esta semana: ${data.totalDrive} PDFs en Drive\n` +
  `✅ Enviados: ${data.totalEnviados}\n` +
  `❌ Sin enviar: ${data.totalPendientes}\n\n` +
  `Sin enviar a sublimarte:${lista}\n\n` +
  `Enviar a sublimarte.alqueria@gmail.com`;

return [{ json: { mensaje } }];
